const fmt = (n) => n >= 1000 ? `$${(n/1000).toFixed(n>=10000?0:1)}k` : `$${n}`;
const fmtFull = (n) => `$${n.toLocaleString()}`;
const pct = (t) => (((t[t.length-1]-t[0])/t[0])*100).toFixed(1);
const gradeColor = (g) => g >= 9.5 ? "#C9A84C" : g >= 9 ? "#A8C0A0" : g >= 7 ? "#CD7F32" : g === 0 ? "#9B59B6" : "#888";
const gradeLabel = (item) => item.gradeNum === 0 ? (item.grade || "RAW") : item.grade;

function Spark({ trend, color="#22c55e", w=60, h=22 }) {
  const min=Math.min(...trend), max=Math.max(...trend), range=max-min||1;
  const pts = trend.map((v,i) => {
    const x=(i/(trend.length-1))*w;
    const y=h-3-((v-min)/range)*(h-6);
    return `${x},${y}`;
  }).join(" ");
  const area=`0,${h} ${pts} ${w},${h}`;
  const id=`sp${w}${h}${color.replace(/[^a-z0-9]/gi,"")}`;
  return (
    <svg width={w} height={h} viewBox={`0 0 ${w} ${h}`} style={{overflow:"visible"}}>
      <defs>
        <linearGradient id={id} x1="0" y1="0" x2="0" y2="1">
          <stop offset="0%" stopColor={color} stopOpacity="0.3"/>
          <stop offset="100%" stopColor={color} stopOpacity="0"/>
        </linearGradient>
      </defs>
      <polygon points={area} fill={`url(#${id})`}/>
      <polyline points={pts} fill="none" stroke={color} strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round"/>
    </svg>
  );
}

function CardImage({ item }) {
  const src = IMAGES[item.img];
  const isComic = item.type === "comic";
  return (
    <div style={{
      width:"100%", aspectRatio: isComic ? "0.65/1" : "0.72/1",
      borderRadius:8, overflow:"hidden", position:"relative",
      background:`linear-gradient(135deg, ${item.accent}22, ${item.accent}08)`,
      display:"flex", alignItems:"center", justifyContent:"center",
    }}>
      {src ? (
        <img src={src} alt={item.title} style={{
          width:"100%", height:"100%", objectFit:"contain",
          display:"block",
        }}/>
      ) : (
        <div style={{width:"100%",height:"100%",display:"flex",alignItems:"center",justifyContent:"center",fontSize:36}}>🃏</div>
      )}
      {item.serial && (
        <div style={{
          position:"absolute", bottom:6, right:6,
          background:"rgba(0,0,0,0.75)", backdropFilter:"blur(4px)",
          color:"#C9A84C", fontSize:10, fontWeight:700,
          padding:"2px 7px", borderRadius:10, letterSpacing:"0.08em",
        }}>{item.serial}</div>
      )}
    </div>
  );
}

function GridCard({ item, onTap, theme: t }) {
  const p = parseFloat(pct(item.trend));
  const gc = gradeColor(item.gradeNum);
  const [pressed, setPressed] = useState(false);
  const th = t || { card:"#fff", cardBorder:"#efefef", text:"#111", sub:"#aaa", muted:"#ccc" };
  return (
    <div
      onClick={() => onTap(item)}
      onTouchStart={() => setPressed(true)}
      onTouchEnd={() => setPressed(false)}
      style={{
        background:th.card, borderRadius:16,
        border:`1px solid ${th.cardBorder}`, overflow:"hidden",
        cursor:"pointer", transition:"transform 0.12s, box-shadow 0.12s, background 0.3s",
        transform: pressed ? "scale(0.97)" : "scale(1)",
        boxShadow: pressed ? "none" : "0 2px 12px rgba(0,0,0,0.05)",
      }}
    >
      <div style={{padding:"10px 10px 8px"}}>
        <CardImage item={item}/>
      </div>
      <div style={{padding:"0 10px 10px"}}>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:3}}>
          <div style={{
            fontFamily:"'Playfair Display',Georgia,serif",
            fontSize:13,fontWeight:700,color:th.text,lineHeight:1.2,
            flex:1,marginRight:5,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap",
          }}>{item.title}</div>
          <span style={{
            fontSize:9,fontWeight:700,letterSpacing:"0.06em",
            padding:"2px 6px",borderRadius:20,flexShrink:0,
            background:`${gc}18`, color:gc, border:`1px solid ${gc}40`,
          }}>{gradeLabel(item)}</span>
        </div>
        <div style={{fontSize:9,color:th.muted,marginBottom:8,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>
          {item.subtitle}
        </div>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-end"}}>
          <div>
            <div style={{fontFamily:"'Playfair Display',Georgia,serif",fontSize:15,fontWeight:700,color:th.text}}>
              {fmt(item.value)}
            </div>
            <div style={{fontSize:10,fontWeight:600,color:p>=0?"#22c55e":"#ef4444"}}>
              {p>=0?"+":""}{p}%
            </div>
          </div>
          <Spark trend={item.trend} color={p>=0?"#22c55e":"#ef4444"}/>
        </div>
      </div>
    </div>
  );
}

function DetailSheet({ item, onClose, theme: t }) {
  const th = t || { sheetBg:"#fff", text:"#111", sub:"#aaa", muted:"#ccc", metaBg:"#fafafa", stripBorder:"#f5f5f5" };
  const p = parseFloat(pct(item.trend));
  const gc = gradeColor(item.gradeNum);
  const months = ["Oct","Nov","Dec","Jan","Feb","Mar","Apr"];
  const startY = useRef(null);
  useEffect(()=>{ document.body.style.overflow="hidden"; return ()=>{ document.body.style.overflow=""; }; },[]);
  return (
    <div style={{position:"fixed",inset:0,zIndex:200,display:"flex",flexDirection:"column",justifyContent:"flex-end"}}>
      <div onClick={onClose} style={{position:"absolute",inset:0,background:"rgba(0,0,0,0.5)",backdropFilter:"blur(8px)",animation:"fadeIn 0.2s ease"}}/>
      <div
        onTouchStart={e=>{ startY.current=e.touches[0].clientY; }}
        onTouchEnd={e=>{ if(startY.current && e.changedTouches[0].clientY-startY.current>60) onClose(); }}
        style={{
          position:"relative",zIndex:1,background:th.sheetBg,
          borderRadius:"24px 24px 0 0",maxHeight:"90vh",overflowY:"auto",
          animation:"slideUp 0.3s cubic-bezier(0.34,1.4,0.64,1)",
          WebkitOverflowScrolling:"touch", transition:"background 0.3s",
        }}
      >
        <div style={{display:"flex",justifyContent:"center",padding:"12px 0 0"}}>
          <div style={{width:36,height:4,borderRadius:2,background:th.stripBorder}}/>
        </div>

        <div style={{padding:"16px 20px 0"}}>
          <div style={{display:"flex",gap:14,marginBottom:18}}>
            <div style={{width:120,flexShrink:0}}>
              <CardImage item={item}/>
            </div>
            <div style={{flex:1,minWidth:0}}>
              <div style={{display:"flex",gap:5,marginBottom:10,flexWrap:"wrap"}}>
                <span style={{
                  fontSize:9,letterSpacing:"0.15em",textTransform:"uppercase",fontWeight:700,
                  padding:"3px 8px",borderRadius:20,
                  background:item.type==="nba"?"#FFF3CD":"#F0EEFF",
                  color:item.type==="nba"?"#9A6F00":"#5B4FCF",
                  border:`1px solid ${item.type==="nba"?"#E8C84A":"#C4B8FF"}`,
                }}>{item.type==="nba"?"NBA Card":"Comic Book"}</span>
                <span style={{
                  fontSize:9,fontWeight:700,letterSpacing:"0.1em",
                  padding:"3px 8px",borderRadius:20,
                  background:`${gc}18`, color:gc, border:`1px solid ${gc}40`,
                }}>{gradeLabel(item)}</span>
                {item.serial && <span style={{fontSize:9,fontWeight:700,padding:"3px 8px",borderRadius:20,background:"#2a2a2a",color:"#C9A84C",border:"1px solid #C9A84C40"}}>#{item.serial}</span>}
              </div>
              <div style={{fontFamily:"'Playfair Display',Georgia,serif",fontSize:22,fontWeight:900,color:th.text,lineHeight:1.1,marginBottom:4}}>{item.title}</div>
              <div style={{fontSize:11,color:th.sub,lineHeight:1.4}}>{item.subtitle}</div>
            </div>
          </div>

          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10,marginBottom:16,background:th.metaBg,borderRadius:14,padding:"12px 14px",transition:"background 0.3s"}}>
            {[
              {label:"Year",value:item.year},
              {label:item.type==="comic"?"Publisher":"Team",value:item.type==="comic"?item.publisher:item.team},
              {label:"Grade",value:gradeLabel(item)},
              {label:item.type==="comic"?"Era":"Set",value:item.type==="comic"?(item.year<1970?"Silver Age":item.year<1985?"Bronze Age":"Copper Age"):item.tags[0]},
            ].map(({label,value})=>(
              <div key={label}>
                <div style={{fontSize:9,letterSpacing:"0.1em",textTransform:"uppercase",color:th.muted,marginBottom:2}}>{label}</div>
                <div style={{fontSize:12,fontWeight:700,color:th.text}}>{value}</div>
              </div>
            ))}
          </div>

          <div style={{display:"flex",gap:5,flexWrap:"wrap",marginBottom:18}}>
            {item.tags.map(tag=>(
              <span key={tag} style={{fontSize:10,letterSpacing:"0.06em",textTransform:"uppercase",padding:"4px 9px",borderRadius:6,background:`${item.accent}12`,color:item.accent,fontWeight:600,border:`1px solid ${item.accent}22`}}>{tag}</span>
            ))}
          </div>
        </div>

        <div style={{borderTop:`1px solid ${th.stripBorder}`,padding:"18px 20px 0"}}>
          <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-end",marginBottom:14}}>
            <div>
              <div style={{fontSize:9,letterSpacing:"0.12em",textTransform:"uppercase",color:th.muted,marginBottom:3}}>Est. Value</div>
              <div style={{fontFamily:"'Playfair Display',Georgia,serif",fontSize:30,fontWeight:900,color:th.text,lineHeight:1}}>{fmtFull(item.value)}</div>
            </div>
            <div style={{textAlign:"right"}}>
              <div style={{fontSize:9,letterSpacing:"0.12em",textTransform:"uppercase",color:th.muted,marginBottom:3}}>6-Month</div>
              <div style={{fontSize:18,fontWeight:700,color:p>=0?"#22c55e":"#ef4444"}}>{p>=0?"+":""}{p}%</div>
            </div>
          </div>
          {(()=>{
            const W=320,H=72;
            const min=Math.min(...item.trend),max=Math.max(...item.trend),range=max-min||1;
            const pts=item.trend.map((v,i)=>({
              x:(i/(item.trend.length-1))*(W-16)+8,
              y:H-12-((v-min)/range)*(H-22),
            }));
            const line=pts.map(p=>`${p.x},${p.y}`).join(" ");
            const area=`8,${H} ${line} ${W-8},${H}`;
            const cid=`det${item.id}`;
            return (
              <svg width="100%" viewBox={`0 0 ${W} ${H}`} style={{overflow:"visible",marginBottom:6}}>
                <defs>
                  <linearGradient id={cid} x1="0" y1="0" x2="0" y2="1">
                    <stop offset="0%" stopColor="#22c55e" stopOpacity="0.18"/>
                    <stop offset="100%" stopColor="#22c55e" stopOpacity="0"/>
                  </linearGradient>
                </defs>
                <polygon points={area} fill={`url(#${cid})`}/>
                <polyline points={line} fill="none" stroke="#22c55e" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
                {pts.map((p,i)=>(
                  <g key={i}>
                    <circle cx={p.x} cy={p.y} r={3} fill={th.sheetBg} stroke="#22c55e" strokeWidth="1.8"/>
                    <text x={p.x} y={H+2} fontSize="8" fill={th.muted} textAnchor="middle" fontFamily="'DM Sans',system-ui">{months[i]}</text>
                  </g>
                ))}
              </svg>
            );
          })()}
        </div>
        <div style={{height:36}}/>
      </div>
    </div>
  );
}


export default function VaultApp() {
  const [tab,setTab] = useState("nba");
  const [sortNba,setSortNba] = useState("grade-desc");
  const [sortComic,setSortComic] = useState("value-desc");
  const [search,setSearch] = useState("");
  const [selected,setSelected] = useState(null);
  const [showSearch,setShowSearch] = useState(false);
  const [dark,setDark] = useState(false);
  const searchRef = useRef(null);

  const sort = tab === "nba" ? sortNba : sortComic;
  const setSort = tab === "nba" ? setSortNba : setSortComic;

  const t = {
    bg: dark ? "#0F0F0F" : "#F7F7F5",
    card: dark ? "#1A1A1A" : "#fff",
    cardBorder: dark ? "#2A2A2A" : "#efefef",
    header: dark ? "#0F0F0F" : "#F7F7F5",
    text: dark ? "#F0F0F0" : "#111",
    sub: dark ? "#888" : "#aaa",
    muted: dark ? "#555" : "#ccc",
    strip: dark ? "#1A1A1A" : "#fff",
    stripBorder: dark ? "#222" : "#e8e8e8",
    inputBg: dark ? "#1A1A1A" : "#fff",
    inputBorder: dark ? "#333" : "#e0e0e0",
    tabActive: dark ? "#F0F0F0" : "#111",
    tabActiveTxt: dark ? "#111" : "#fff",
    tabInactive: dark ? "#444" : "#aaa",
    sheetBg: dark ? "#161616" : "#fff",
    metaBg: dark ? "#1F1F1F" : "#fafafa",
  };

  const totalValue = COLLECTION.reduce((s,i)=>s+i.value,0);

  useEffect(()=>{ if(showSearch) searchRef.current?.focus(); },[showSearch]);

  const items = COLLECTION
    .filter(i=>i.type===tab)
    .filter(i=>!search||i.title.toLowerCase().includes(search.toLowerCase())||i.subtitle.toLowerCase().includes(search.toLowerCase()))
    .sort((a,b)=>{
      if(sort==="value-desc") return b.value-a.value;
      if(sort==="value-asc") return a.value-b.value;
      if(sort==="grade-desc") return b.gradeNum-a.gradeNum;
      if(sort==="year-asc") return a.year-b.year;
      if(sort==="year-desc") return b.year-a.year;
      return 0;
    });

  return (
    <div style={{minHeight:"100vh",background:t.bg,fontFamily:"'DM Sans',system-ui,sans-serif",maxWidth:900,margin:"0 auto",transition:"background 0.3s"}}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Playfair+Display:wght@700;900&family=DM+Sans:wght@300;400;500;600;700&display=swap');
        *{box-sizing:border-box;margin:0;padding:0;-webkit-tap-highlight-color:transparent;}
        @keyframes fadeIn{from{opacity:0}to{opacity:1}}
        @keyframes slideUp{from{opacity:0;transform:translateY(40px)}to{opacity:1;transform:translateY(0)}}
        @keyframes fadeSlide{from{opacity:0;transform:translateY(-6px)}to{opacity:1;transform:translateY(0)}}
        input::placeholder{color:#bbb;} ::-webkit-scrollbar{display:none;}
      `}</style>

      {/* HEADER */}
      <div style={{padding:"52px 20px 0",background:t.header,position:"sticky",top:0,zIndex:100,transition:"background 0.3s"}}>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:18}}>
          <div>
            <div style={{fontSize:9,letterSpacing:"0.24em",textTransform:"uppercase",color:t.sub,fontWeight:600,marginBottom:6}}>My Collection</div>
            <div style={{fontFamily:"'Playfair Display',Georgia,serif",fontSize:32,fontWeight:900,color:t.text,letterSpacing:"-0.02em",lineHeight:1}}>The Vault.</div>
          </div>
          <div style={{display:"flex",gap:8}}>
            <button onClick={()=>setDark(d=>!d)} style={{
              width:40,height:40,borderRadius:20,
              border:`1px solid ${t.stripBorder}`,
              background:t.card, color:t.text,
              fontSize:16,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",
              transition:"all 0.2s",
            }}>{dark?"☀️":"🌙"}</button>
            <button onClick={()=>setShowSearch(s=>!s)} style={{
              width:40,height:40,borderRadius:20,
              border:`1px solid ${t.stripBorder}`,
              background:showSearch?t.tabActive:t.card,
              color:showSearch?t.tabActiveTxt:t.text,
              fontSize:18,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",
              transition:"all 0.2s",
            }}>⌕</button>
          </div>
        </div>

        {/* Stats strip */}
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:1,background:t.stripBorder,borderRadius:14,overflow:"hidden",marginBottom:14}}>
          {[
            {label:"Portfolio",value:fmt(totalValue),sub:`${COLLECTION.length} items`},
            {label:"NBA Cards",value:`${COLLECTION.filter(c=>c.type==="nba").length}`,sub:"in vault"},
            {label:"Comics",value:`${COLLECTION.filter(c=>c.type==="comic").length}`,sub:"cgc slabs"},
          ].map(({label,value,sub})=>(
            <div key={label} style={{background:t.strip,padding:"10px 0",textAlign:"center",transition:"background 0.3s"}}>
              <div style={{fontSize:9,color:t.muted,letterSpacing:"0.1em",textTransform:"uppercase",marginBottom:2}}>{label}</div>
              <div style={{fontFamily:"'Playfair Display',Georgia,serif",fontSize:17,fontWeight:900,color:t.text}}>{value}</div>
              <div style={{fontSize:9,color:t.muted}}>{sub}</div>
            </div>
          ))}
        </div>

        {showSearch&&(
          <div style={{marginBottom:12,animation:"fadeSlide 0.2s ease"}}>
            <input ref={searchRef} value={search} onChange={e=>setSearch(e.target.value)}
              placeholder={`Search ${tab==="nba"?"players":"comics"}...`}
              style={{width:"100%",padding:"10px 16px",borderRadius:12,border:`1px solid ${t.inputBorder}`,fontSize:14,color:t.text,background:t.inputBg,outline:"none"}}
            />
          </div>
        )}

        <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",paddingBottom:14}}>
          <div style={{display:"flex",gap:2}}>
            {[{id:"nba",label:"NBA Cards"},{id:"comic",label:"Comics"}].map(tb=>(
              <button key={tb.id} onClick={()=>{setTab(tb.id);setSearch("");}} style={{
                padding:"6px 16px",borderRadius:100,border:"none",cursor:"pointer",
                fontSize:12,fontWeight:600,transition:"all 0.15s",
                background:tab===tb.id?t.tabActive:"transparent",
                color:tab===tb.id?t.tabActiveTxt:t.tabInactive,
              }}>{tb.label}</button>
            ))}
          </div>
          <select value={sort} onChange={e=>setSort(e.target.value)} style={{
            fontSize:11,color:t.sub,background:"transparent",border:"none",outline:"none",
            cursor:"pointer",fontFamily:"'DM Sans',system-ui",fontWeight:600,
          }}>
            <option value="value-desc">Value ↓</option>
            <option value="value-asc">Value ↑</option>
            <option value="grade-desc">Grade</option>
            <option value="year-asc">Year ↑</option>
            <option value="year-desc">Year ↓</option>
          </select>
        </div>
      </div>

      {/* GRID */}
      <div style={{padding:"8px 20px 100px"}}>
        <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill, minmax(180px, 1fr))",gap:12}}>
          {items.map(item=><GridCard key={item.id} item={item} onTap={setSelected} theme={t}/>)}
        </div>
        {items.length===0&&(
          <div style={{textAlign:"center",padding:"60px 0"}}>
            <div style={{fontSize:36,marginBottom:10}}>🔍</div>
            <div style={{fontFamily:"'Playfair Display',Georgia,serif",fontSize:18,color:t.sub}}>Nothing found</div>
          </div>
        )}
      </div>

      {selected&&<DetailSheet item={selected} onClose={()=>setSelected(null)} theme={t}/>}
    </div>
  );
}
